/// cache and `package.searchers` to find and load it if not already cached.
///
/// Returns the module value (and optionally the loader data) — 2 values.
///
/// C: `static int ll_require(lua_State *L)`
pub fn ll_require(state: &mut LuaState) -> Result<usize, LuaError> {
    // C: const char *name = luaL_checkstring(L, 1);
    let name = state.check_arg_string(1)?.to_vec();

    // C: lua_settop(L, 1);  -- LOADED table will be at index 2
    // PORT NOTE: must use the public-API `set_top` (relative to the current
    // C-frame's `func`), not `LuaState::set_top` which is an inherent that
    // sets an absolute stack index and would truncate the entire stack.
    lua_vm::api::set_top(state, 1)?;

    // C: lua_getfield(L, LUA_REGISTRYINDEX, LUA_LOADED_TABLE);
    state.get_field_registry(b"_LOADED")?;

    // C: lua_getfield(L, 2, name);  -- LOADED[name]
    state.get_field(2, &name)?;

    // C: if (lua_toboolean(L, -1)) return 1;  -- package is already loaded
    if state.to_boolean(-1) {
        return Ok(1);
    }

    // C: lua_pop(L, 1);  -- remove 'getfield' result
    state.pop_n(1);

    // C: findloader(L, name);
    // After this, the stack has: [name(1), LOADED(2), searchers(3), loader(-2), loaderdata(-1)]
    findloader(state, &name)?;

    // C: lua_rotate(L, -2, 1);  -- function <-> loader data
    // Swaps loader and loaderdata: [..., loaderdata, loader]
    state.rotate(-2, 1);

    // C: lua_pushvalue(L, 1);  -- name is 1st argument to module loader
    state.push_value(1);

    // C: lua_pushvalue(L, -3);  -- loader data is 2nd argument
    // PORT NOTE: After the rotate, loaderdata is 3 from top (-3). In C this is
    // at absolute index 4 (but C uses the pre-rotate layout). TODO(port): verify.
    state.push_value(-3);

    // C: lua_call(L, 2, 1);  -- run loader to load module
    state.call(2, 1)?;

    // C: if (!lua_isnil(L, -1)) lua_setfield(L, 2, name);
    if state.type_at(-1) != LuaType::Nil {
        state.set_field(2, &name)?;
    } else {
        // C: else lua_pop(L, 1);
        state.pop_n(1);
    }

    // C: if (lua_getfield(L, 2, name) == LUA_TNIL) { ... module set no value }
    let ty = state.get_field(2, &name)?;
    if ty == LuaType::Nil {
        // C: lua_pushboolean(L, 1); lua_copy(L, -1, -2); lua_setfield(L, 2, name);
        state.push(LuaValue::Bool(true));
        state.copy_value(-1, -2);
        state.set_field(2, &name)?;
    }

    // C: lua_rotate(L, -2, 1);  -- loader data <-> module result
    state.rotate(-2, 1);

    // C: return 2;  -- return module result and loader data
    Ok(2)
}

// ── Package library setup ─────────────────────────────────────────────────────

/// Create the `searchers` table and install the four built-in searchers, each
/// with the `package` table as upvalue #1.
///
/// C: `static void createsearcherstable(lua_State *L)`
fn createsearcherstable(state: &mut LuaState) -> Result<(), LuaError> {
    // C: static const lua_CFunction searchers[] = { searcher_preload,
    //        searcher_Lua, searcher_C, searcher_Croot, NULL };
    let searchers: &[fn(&mut LuaState) -> Result<usize, LuaError>] = &[
        searcher_preload,
        searcher_lua,
        searcher_c,
        searcher_croot,
    ];

    // C: lua_createtable(L, sizeof(searchers)/sizeof(searchers[0]) - 1, 0);
    state.create_table(searchers.len() as i32, 0);

    // C: for (i=0; searchers[i] != NULL; i++) { ... lua_pushcclosure(L, searchers[i], 1); ... }
    for (i, &f) in searchers.iter().enumerate() {
        // C: lua_pushvalue(L, -2);  -- set 'package' as upvalue for all searchers
        state.push_value(-2);
        // C: lua_pushcclosure(L, searchers[i], 1);
        // TODO(port): push_c_closure takes the function and n upvalues from the
        //             stack. The package table upvalue must be correctly associated
        //             with each searcher closure so that findfile can access it
        //             via lua_upvalueindex(1). Verify in Phase B.

//! Initialization of standard libraries for Lua.
//!
//! Opens all standard libraries via `require`-style loading and registers
//! them into the global table.
//!
//! Port of `src/linit.c` (66 lines, 1 function).

use crate::state_stub::{LuaState, LuaStateStubExt as _, lua_CFunction, upvalue_index, CompareOp, LuaDebug};
use lua_types::error::LuaError;

// C: lua_CFunction — fn pointer type for Lua-callable C functions.
// Matches types.tsv: lua_CFunction → fn(&mut LuaState) -> Result<usize, LuaError>
type LuaCFunction = fn(&mut LuaState) -> Result<usize, LuaError>;

// ── Library-name byte-string constants ────────────────────────────────────
//
// These replace the C macros from lualib.h and lauxlib.h:
//   LUA_GNAME        = "_G"         (lauxlib.h)
//   LUA_LOADLIBNAME  = "package"    (lualib.h)
//   LUA_COLIBNAME    = "coroutine"  (lualib.h)
//   LUA_TABLIBNAME   = "table"      (lualib.h)
//   LUA_IOLIBNAME    = "io"         (lualib.h)
//   LUA_OSLIBNAME    = "os"         (lualib.h)
//   LUA_STRLIBNAME   = "string"     (lualib.h)
//   LUA_MATHLIBNAME  = "math"       (lualib.h)
//   LUA_UTF8LIBNAME  = "utf8"       (lualib.h)
//   LUA_DBLIBNAME    = "debug"      (lualib.h)
//
// Per PORTING.md §3.1 all Lua string data uses &[u8], not &str.

// C: static const luaL_Reg loadedlibs[] = {
//   {LUA_GNAME, luaopen_base},
//   {LUA_LOADLIBNAME, luaopen_package},
//   {LUA_COLIBNAME, luaopen_coroutine},
//   {LUA_TABLIBNAME, luaopen_table},
//   {LUA_IOLIBNAME, luaopen_io},
//   {LUA_OSLIBNAME, luaopen_os},
//   {LUA_STRLIBNAME, luaopen_string},
//   {LUA_MATHLIBNAME, luaopen_math},
//   {LUA_UTF8LIBNAME, luaopen_utf8},
//   {LUA_DBLIBNAME, luaopen_debug},
//   {NULL, NULL}
// };
//
// PORT NOTE: C sentinel `{NULL, NULL}` dropped — Rust slices carry their
//   own length, so no terminator is needed.
//
// PORT NOTE: Per PORTING.md §7, `luaopen_X` → `open` inside the module
//   (e.g. `crate::base::open`, `crate::string_lib::open`).  As of Phase A
//   the individual stdlib modules exported inconsistent names:
//     base.rs        → `pub fn open`          (canonical; matches here)
//     string_lib.rs  → `pub fn luaopen_string` (needs rename in Phase B)
//     table_lib.rs   → `pub fn open_table`    (needs rename in Phase B)
//     math_lib.rs    → `pub fn luaopen_math`  (needs rename in Phase B)
//     io_lib.rs      → `pub fn luaopen_io`    (needs rename in Phase B)
//     os_lib.rs      → `pub fn open_os`       (needs rename in Phase B)
//     utf8_lib, debug_lib, coro_lib, loadlib  → not yet ported (Phase B)
//   Phase B should rename every stdlib opener to `pub fn open` and update
//   this table accordingly.
static LOADED_LIBS: &[(&[u8], LuaCFunction)] = &[
    (b"_G",         crate::base::open),
    (b"package",    crate::loadlib::luaopen_package),
    (b"coroutine",  crate::coro_lib::open_coroutine),
    (b"table",      crate::table_lib::open_table),
    (b"io",         crate::io_lib::luaopen_io),
    (b"os",         crate::os_lib::open_os),
    (b"string",     crate::string_lib::luaopen_string),
    (b"math",       crate::math_lib::luaopen_math),
    (b"utf8",       crate::utf8_lib::open_utf8),
    (b"debug",      crate::debug_lib::open_debug),
];

// C: LUALIB_API void luaL_openlibs (lua_State *L) {
//   const luaL_Reg *lib;
//   /* "require" functions from 'loadedlibs' and set results to global table */
//   for (lib = loadedlibs; lib->func; lib++) {
//     luaL_requiref(L, lib->name, lib->func, 1);
//     lua_pop(L, 1);  /* remove lib */
//   }
// }
//
// PORT NOTE: `LUALIB_API` → `pub` (PORTING.md §4.1 / macros.tsv).
//   `luaL_requiref(L, name, func, 1)` → `state.require_lib(name, func, true)?`
//   The final `1` argument means "set global" — the loaded module value is
//   assigned to the global table under `name` and the value left on the
//   stack is then discarded by `lua_pop(L, 1)`.
//   `lua_pop(L, 1)` → `state.pop_n(1)` (macros.tsv).
/// Open all standard Lua libraries into `state`, registering each into the
/// global table.
///
/// Corresponds to `luaL_openlibs` in `linit.c`.
pub fn open_libs(state: &mut LuaState) -> Result<(), LuaError> {
    for &(name, func) in LOADED_LIBS {
        // C: luaL_requiref(L, lib->name, lib->func, 1);
        state.require_lib(name, func, true)?;
        // C: lua_pop(L, 1);  /* remove lib */
        state.pop_n(1);
    }
    Ok(())
}

