26	fn file_loader_hook(filename: &[u8]) -> Result<Vec<u8>, LuaError> {
27	    #[cfg(unix)]
28	    let path: std::path::PathBuf = {
29	        use std::os::unix::ffi::OsStrExt;
30	        std::path::PathBuf::from(std::ffi::OsStr::from_bytes(filename))
31	    };
32	    #[cfg(not(unix))]
33	    let path: std::path::PathBuf = {
34	        let s = std::str::from_utf8(filename).map_err(|_| {
35	            LuaError::runtime(format_args!("filename is not valid UTF-8"))
36	        })?;
37	        std::path::PathBuf::from(s)
38	    };
39	    std::fs::read(&path).map_err(|err| {
40	        LuaError::runtime(format_args!(
41	            "cannot open '{}': {}",
